import { readFileSync } from "node:fs";
import { quote, claim, cap } from "./claim-office.js";

const input = readFileSync(0, "utf-8");
const scenario = JSON.parse(input);

const results: Array<Record<string, number>> = [];
const policies: Array<{ items: any[]; remainingCap: number }> = [];
let previousContracts = 0;

for (const step of scenario.steps) {
  if (step.op === "quote") {
    const premium = quote({
      customer: {
        yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
        previousContracts,
      },
      items: step.items,
    });
    results.push({ premium });
    policies.push({ items: step.items, remainingCap: cap(step.items) });
    previousContracts += 1;
  } else if (step.op === "claim") {
    const policy = policies[step.policy];
    const result = claim({
      policy: { items: policy.items, remainingCap: policy.remainingCap },
      incident: step.incident,
    });
    policy.remainingCap = result.remainingCap;
    results.push({ payout: result.payout, remainingCap: result.remainingCap });
  }
}

process.stdout.write(JSON.stringify({ results }));

